// RegisterValidator registers a Validator implementation with the C runtime.
func RegisterValidator(impl Validator) error {
	handle := cgo.NewHandle(impl)

	// Build the C vtable
	vtable := C.kreuzberg_validator_VTable{
		validate: C.goValidatorValidate,
		should_validate: C.goValidatorShouldValidate,
		priority: C.goValidatorPriority,
		name: C.goValidatorName,
		version: C.goValidatorVersion,
		initialize: C.goValidatorInitialize,
		shutdown: C.goValidatorShutdown,
		free_user_data: C.goValidatorFreeUserData,
	}

	// Call C registration
	cName := C.CString(impl.Name())
	defer C.free(unsafe.Pointer(cName))

	var cErr *C.char
	rc := C.kreuzberg_validator_register(
		cName,
		unsafe.Pointer(&vtable),
		unsafe.Pointer(uintptr(handle)),
		&cErr,
	)

	if rc != 0 {
		msg := "failed to register Validator"
		if cErr != nil {
			msg = C.GoString(cErr)
			C.free(unsafe.Pointer(cErr))
		}
		handle.Delete()
		return fmt.Errorf("%s", msg)
	}

	return nil
}

